+func (m *Model) computeColumns(count int) int {
+	cols := 1
+	if count >= 4 && m.width >= 80 {
+		cols = 2
+	}
+	if count >= 6 && m.width >= 120 {
+		cols = min(3, count)
+	}
+	if count >= 9 && m.width >= 160 {
+		cols = min(4, count)
+	}
+	return cols
+}
+
+func min(a, b int) int {
+	if a < b {
+		return a
+	}
+	return b
+}
